219	function createMultipartResponseHandler() {
220	  return async ({
221	    response,
222	  }: {
223	    response: Response;
224	  }): Promise<{
225	    value: MultipartResult;
226	    responseHeaders: Record<string, string>;
227	  }> => {
228	    const contentType = response.headers.get('content-type') ?? '';
229	    const responseHeaders: Record<string, string> = {};
230	    response.headers.forEach((value, key) => {
231	      responseHeaders[key] = value;
232	    });
233	
234	    const boundaryMatch = contentType.match(/boundary=([^\s;]+)/);
235	    if (!boundaryMatch) {
236	      throw new Error(
237	        `Prodia response missing multipart boundary in content-type: ${contentType}`,
238	      );
239	    }
240	    const boundary = boundaryMatch[1];
241	
242	    const arrayBuffer = await response.arrayBuffer();
243	    const bytes = new Uint8Array(arrayBuffer);
244	
245	    const parts = parseMultipart(bytes, boundary);
246	
247	    let jobResult: ProdiaJobResult | undefined;
248	    let imageBytes: Uint8Array | undefined;
249	
250	    for (const part of parts) {
251	      const contentDisposition = part.headers['content-disposition'] ?? '';
252	      const partContentType = part.headers['content-type'] ?? '';
253	
254	      if (contentDisposition.includes('name="job"')) {
255	        const jsonStr = new TextDecoder().decode(part.body);
256	        jobResult = await parseJSON({
257	          text: jsonStr,
258	          schema: zodSchema(prodiaJobResultSchema),
259	        });
260	      } else if (contentDisposition.includes('name="output"')) {
261	        imageBytes = part.body;
262	      } else if (partContentType.startsWith('image/')) {
263	        imageBytes = part.body;
264	      }
265	    }
266	
267	    if (!jobResult) {
268	      throw new Error('Prodia multipart response missing job part');
269	    }
270	    if (!imageBytes) {
271	      throw new Error('Prodia multipart response missing output image');
272	    }
273	
274	    return {
275	      value: { jobResult, imageBytes },
276	      responseHeaders,
277	    };
278	  };
