     images: response.images.map(i => i.b64_json),
     warnings,
     response: { timestamp: new Date(), modelId: this.modelId, headers: responseHeaders },
     providerMetadata: { pixelart: { images: response.images.map(() => ({})) } },
   }
   ```

### Step 8 — `packages/pixelart/src/pixelart-provider.ts`

Exports `PixelArtProvider` interface, `PixelArtProviderSettings` interface, and `createPixelArt` factory:

```typescript
// PixelArtProvider — image-only, no ProviderV3 extension needed
export interface PixelArtProvider {
  image(modelId: PixelArtImageModelId, settings?: PixelArtImageSettings): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId, settings?: PixelArtImageSettings): ImageModelV3;
}

export interface PixelArtProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://api.pixelart.ai/v1';

  const getHeaders = () => ({
    Authorization: `Bearer ${loadApiKey({
      apiKey: options.apiKey,
      environmentVariableName: 'PIXELART_API_KEY',
      description: 'PixelArt',
    })}`,
    ...options.headers,
  });

  const createImageModel = (modelId, settings = {}) =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart.image',
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return { image: createImageModel, imageModel: createImageModel };
}

export const pixelart = createPixelArt();
```

