import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtConfig } from './pixelart-config';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Response schema — matches the fictional PixelArt API contract
// ---------------------------------------------------------------------------

const pixelArtImageResponseSchema = z.object({
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
  model: z.string().nullish(),
  created: z.number().nullish(),
});

// ---------------------------------------------------------------------------
// Error schema — used to extract a human-readable message from API errors
// ---------------------------------------------------------------------------

const pixelArtErrorDataSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.union([z.string(), z.number()]).nullish(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorDataSchema,
  errorToMessage: data => data.error.message,
});

// ---------------------------------------------------------------------------
// Image model implementation
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * PixelArt generates one image per API call.
   */
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    files,
    mask,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the size setting instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support a random seed.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image editing with input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting masks.',
      });
    }

    // Provider-specific options passed via providerOptions.pixelart
    const pixelArtOptions = (providerOptions.pixelart ??
      {}) as PixelArtImageSettings;

    // Build the request body.
    // Priority: providerOptions.pixelart > doGenerate params > constructor settings
    const requestBody = {
      model: this.modelId,
      prompt,
      n,
      size: pixelArtOptions.size ?? size ?? this.settings.size,
      style: pixelArtOptions.style ?? this.settings.style,
      pixel_density:
        pixelArtOptions.pixelDensity ?? this.settings.pixelDensity,
    };

    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(image => image.b64_json),
      warnings,
      response: {
        timestamp: new Date(),
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.images.map(() => ({})),
        },
      },
    };
  }
}

